class LogicGate:
 def __init__(self, name, delay_ns=1):
 self.name = name
 self.delay = delay_ns

 def simulate(self, *inputs):
 raise NotImplementedError

class ANDGate(LogicGate):
 def simulate(self, a, b):
 return a & b

class ORGate(LogicGate):
 def simulate(self, a, b):
 return a | b

class NOTGate(LogicGate):
 def simulate(self, a):
 return 1 - a

class NANDGate(LogicGate):
 def simulate(self, a, b):
 return 1 - (a & b)

class XORGate(LogicGate):
 def simulate(self, a, b):
 return a ^ b

# Example: Build a half adder (Sum = A XOR B, Carry = A AND B)
xor_gate = XORGate("XOR1")
and_gate = ANDGate("AND1")

A, B = 1, 1
sum_bit = xor_gate.simulate(A, B) # 0
carry = and_gate.simulate(A, B) # 1
print(f"Half Adder: {A}+{B} = Sum:{sum_bit}, Carry:{carry}")

class Circuit:
 def __init__(self):
 self.gates = []
 self.wires = {}

 def add_input(self, name, value):
 self.wires[name] = value

 def add_gate(self, gate_type, inputs, output_name):
 self.gates.append((gate_type, inputs, output_name))

 def evaluate(self):
 for gate_type, inputs, output in self.gates:
 input_values = [self.wires[i] for i in inputs]
 if gate_type == 'AND':
 result = input_values[0] & input_values[1]
 elif gate_type == 'OR':
 result = input_values[0] | input_values[1]
 elif gate_type == 'NOT':
 result = 1 - input_values[0]
 elif gate_type == 'XOR':
 result = input_values[0] ^ input_values[1]
 self.wires[output] = result
 return self.wires

# Example: Build F = A.B + C
circuit = Circuit()
circuit.add_input('A', 1)
circuit.add_input('B', 0)
circuit.add_input('C', 1)
circuit.add_gate('AND', ['A', 'B'], 'T1') # T1 = A.B
circuit.add_gate('OR', ['T1', 'C'], 'F') # F = T1 + C

result = circuit.evaluate()
print(f"F = {result['F']}") # Output: F = 1

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity logic_gates is
 Port ( A, B : in STD_LOGIC;
 AND_out : out STD_LOGIC;
 OR_out : out STD_LOGIC;
 NOT_out : out STD_LOGIC;
 NAND_out : out STD_LOGIC;
 NOR_out : out STD_LOGIC;
 XOR_out : out STD_LOGIC;
 XNOR_out : out STD_LOGIC);
end logic_gates;

architecture Behavioral of logic_gates is
begin
 AND_out <= A and B;
 OR_out <= A or B;
 NOT_out <= not A;
 NAND_out <= A nand B;
 NOR_out <= A nor B;
 XOR_out <= A xor B;
 XNOR_out <= A xnor B;
end Behavioral;
